from ..utils.python import PythonCode
from typing import Callable
from irtool.core import BaseIR
from irtool.tools import flatten_layers  # noqa
from mapper.device.CIMA import *

class TorchRTCodeGen(PythonCode):

    def __init__(self, ir, module_name='Inference', inputs=None, outputs=None):
        super().__init__()
        self.ir = ir
        self.module_name = module_name
        self.inputs = inputs
        self.outputs = outputs

    def gen_notes(self):
        yield '''
# **************************************** #
# This file is automatically generated !!! #
#        Please do not modify it !!!      #
# **************************************** #
'''

    def gen_imports(self):
        yield f'from cimruntime.CIMA.simulation.torch_utils import *'


    def gen_layers(self):

        yield from self.gen_notes()
        yield from self.gen_imports()

        yield
        yield

        self.ir.layers = dict(self.ir.iter_layers(deep=False, sorted=True))

        assert isinstance(self.ir, BaseIR), f'invalid IR type={type(self.ir)}'
        layers = self.ir.flatten_layers()

        # init inputs
        inp, oup = self.ir.get_io_layers(layers)

        self.all_node = {}

        self.layer_out_data_type = self.get_data_type(layers)

        self.next_layers = self.get_next_layer(layers)

        for name, layer in layers.items():

            if layer.type == 'input':
                c_ = 0
                for in_ in layer.inputs:
                    self.all_node[f'graph_input:{c_}'] = f'x_graph_input_{c_}'
                    c_ += 1
            elif layer.type == 'op':
                if len(layer.outputs) > 1:
                    c_ = 0
                    for in_ in layer.outputs:
                        self.all_node[f'{name}:{c_}'] = f'x_{name}_{c_}'
                        c_ += 1
                else:
                    self.all_node[f'{name}'] = f'x_{name}'

        # gen forward function
        for name, layer in layers.items():

            if layer.type == 'input':
                c_ = 0
                with self.indent():
                    s_ = ''
                    for in_ in layer.inputs:
                        t = self.all_node[f"graph_input:{c_}"]
                        s_ += f'{t}'
                        if c_ != len(layer.inputs):
                            s_ += f', '
                        c_ += 1
                 # generate function name
                yield f'''def {self.module_name}({s_} weights, activation_lut=None, PE_weight_noise=0, PE_out_noise=0, PE_in_noise=0, ADC_offset=0, device='cpu'):'''

                # gen constant
                constant = self.gen_constants(layers)
                with self.indent():
                    yield f'# Constant Values'
                    for cs in constant:
                        yield cs

            if layer.type == 'op':
                with self.indent():
                    # yield f'# Op Layers: {name}'
                    s_ = self.gen_layer(layer.op.op_id, name, layer)
                    if '\n' in s_:
                        s_1 = s_.split('\n')
                        c = 0
                        for s_2 in s_1:
                            if c != 0:
                                with self.indent(7):
                                    yield s_2
                            else:
                                yield s_2
                            c += 1
                    else:
                        yield s_

            if layer.type == 'output':
                with self.indent():
                    s_ = ''
                    for in_ in layer.inputs:
                        s_ += f'{self.all_node[in_.ref]}, '
                    yield f'return {s_}'

    def gen_constants(self, layers):
        constant_str = []
        for name, layer in layers.items():
            if layer.type == 'op' and layer.op.op_id in ['conv2d', 'matmul', 'fused_conv2d', 'fused_fc']:
                scale = layer.CIMA_calc_info.scale
                offset = layer.CIMA_calc_info.offset
                scale_shift_num = layer.CIMA_calc_info.scale_shift_num
                #     scale_shift_num = [scale_shift_num] * len(scale)
                scale_str_list = []
                offset_str_list = []
                scale_shift_num_str_list = []
                for i in range(len(scale)):
                    if scale[i] != 1 or offset[i] != 0:
                        scale_str_list.append(f'torch.tensor({scale[i]}).to(device)')
                        offset_str_list.append(f'torch.tensor({offset[i]}).to(device)')
                        scale_shift_num_str_list.append(f'{scale_shift_num[i]}')
                if scale_str_list != []:
                    scale_str = f'c_{name}_scale = ['
                    offset_str = f'c_{name}_offset = ['
                    scale_shift_num_str = f'c_{name}_scale_shift_num = ['
                    for i in range(len(scale_str_list)):
                        if i != 0:
                            scale_str += f"\n                      "
                            offset_str += f"\n                       "
                        scale_str += f"{scale_str_list[i]}, "
                        offset_str += f"{offset_str_list[i]}, "
                        scale_shift_num_str += f"{scale_shift_num_str_list[i]}, "

                    scale_str += ']'
                    offset_str += ']'
                    scale_shift_num_str += ']'
                    constant_str.append(scale_str)
                    constant_str.append(offset_str)
                    constant_str.append(scale_shift_num_str)
        return constant_str

    def get_data_type(self, layers):
        layer_data_type = {}
        for name, layer in layers.items():
            if layer.type == 'op':
                layer_data_type[name] = layer.CIMA_calc_info.data_type
        return layer_data_type

    def get_pre_layer(self, layers):
        ''''
        input: {layer_name:layer_object}
        return: {current_layer_name: pre_layer_name}
        '''
        prefix_layer = {}
        for name, layer in layers.items():
            if layer.type not in ['input']:
                prefix_layer[name] =  []
                # get_layer_ref(layers[name].inputs, layers, prefix_layer[name])
                for i in layer.inputs:
                    if 'graph_input' not in i.ref:
                        ref = i.ref
                        if ':' in ref:
                            ref = ref.split(':')[0]
                        # pre_layer = layers[ref]
                        #         prefix_layer[name].append(j.ref)
                        # else:
                        prefix_layer[name].append(ref)
                    else:
                        prefix_layer[name].append(i.ref)

        return prefix_layer

    def get_next_layer(self, layers):
        '''
        input: {layer_name:layer_object}
        return: {current_layer_name: next_layer_name}
        '''
        next_layer = {}
        pre_layer = self.get_pre_layer(layers)
        for k,v in pre_layer.items():
            for name in v:
                next_layer[name] = k
        return next_layer

    def gen_op(self, op_id, *args, **kwargs):
        fn = getattr(self, f'fn_gen_{op_id}', None)
        assert isinstance(fn, Callable), f'fn_gen_{op_id} is not a function'
        return fn(*args, **kwargs)

    def gen_layer(self, op_id, *args, **kwargs):
        return self.gen_op(op_id, *args, **kwargs)

    # conv

    def fn_gen_conv2d(self, layer_name, layer_info):
        # attr
        stride = layer_info.op.stride
        padding = layer_info.op.padding
        scale = layer_info.CIMA_calc_info.scale
        offset = layer_info.CIMA_calc_info.offset
        accumulate_shift_num = layer_info.CIMA_calc_info.accumulate_shift_num
        ADC_quant_level = layer_info.CIMA_calc_info.ADC_quant_level
        # pre layers
        pre_layers = layer_info.inputs[0].ref
        # data type
        if 'graph_input' in pre_layers:
            data_type = layer_info.CIMA_calc_info.data_type
        else:
            if ":" in pre_layers:
                pre_layers_ = pre_layers.split(':')[0]
            else:
                pre_layers_ = pre_layers
            data_type = self.layer_out_data_type[pre_layers_]
        # mappings
        for k,v in layer_info.CIMA_mapping_info.mappings.items():
            device_name = v.device
            break

        # scale first
        if layer_info.CIMA_calc_info.scale_first:
            scale_first = 'True'
        else:
            scale_first = 'False'

        s_ = ''
        if 'dmac' in device_name:

            if layer_info.op.op_id == 'fused_conv2d' and layer_info.op.relu != None:
                relu = 'True'
            else:
                relu = 'False'

            # CIMA_DMACConv_8bit(input_data, weight_data, *, stride=1, padding=0, scale=1, offset=0, scale_shift_num=0, accumulate_shift_num = 0)
            s_ += f"x_{layer_name} = CIMA_DMACConv_8bit({self.all_node[pre_layers]}, weights['{layer_name}.weight'], stride={stride}, padding={padding}, \n"
            if scale[0] != 1 or offset[0] != 0 or len(scale) > 1 or len(offset) > 1:
                # s_ += f"scale=bn_params['{layer_name}']['scale'], offset=bn_params['{layer_name}']['offset'],\nscale_shift_num=bn_params['{layer_name}']['scale_shift_num'], "
                s_ += f"scale=c_{layer_name}_scale, offset=c_{layer_name}_offset, scale_shift_num=c_{layer_name}_scale_shift_num, \n"
                s_ += f'jump_bn=False, '
            s_ += f"accumulate_shift_num={accumulate_shift_num}, relu={relu}, is_scale_first={scale_first})"

        elif 'cima-xb' in device_name:
            if layer_info.op.op_id == 'fused_conv2d' and layer_info.op.relu != None:
                relu = 'True'
            else:
                relu = 'False'

            next_layer = self.next_layers[layer_name]
            if next_layer == 'graph_output':
                next_data_type = data_type
            else:
                assert next_layer in self.layer_out_data_type.keys(), f'{next_layer}'
                next_data_type = self.layer_out_data_type[next_layer]

            if data_type ==  '4bit':

                func_name = 'CIMA_PEConv_4bIN_to_4bOUT'
                if next_data_type == '8bit':
                    func_name = 'CIMA_PEConv_4bIN_to_8bOUT'

                s_ += f"x_{layer_name} = {func_name}({self.all_node[pre_layers]}, weights['{layer_name}.weight'], stride={stride}, padding={padding}, ADC_quant_level={ADC_quant_level}, \n"
                if  scale[0] != 1 or offset[0] != 0 or len(scale) > 1 or len(offset) > 1:
                    # s_ += f"scale=bn_params['{layer_name}']['scale'], offset=bn_params['{layer_name}']['offset'],\nscale_shift_num=bn_params['{layer_name}']['scale_shift_num'], "
                    s_ += f"scale=c_{layer_name}_scale, offset=c_{layer_name}_offset, scale_shift_num=c_{layer_name}_scale_shift_num, "
                # else:
                    # s_ + f'jump_bn=True, '
                s_ += f"accumulate_shift_num={accumulate_shift_num}, \n"

                # noise
                s_ += f"DAC_noise=PE_in_noise, conductance_noise=PE_weight_noise, ADC_noise=PE_out_noise, ADC_offset=ADC_offset, relu={relu}, \n"
                s_ += f"device=device, is_scale_first={scale_first}, )"

            elif data_type == '8bit':
                func_name = 'CIMA_PEConv_8bIN_to_8bOUT'
                if next_data_type == '4bit':
                    func_name = 'CIMA_PEConv_8bIN_to_4bOUT'

                s_ += f"x_{layer_name} = {func_name}({self.all_node[pre_layers]}, weights['{layer_name}.weight'], stride={stride}, padding={padding}, ADC_quant_level={ADC_quant_level}, \n"
                print(f"{layer_name}")
                print("scale, offset:", scale, offset)
                if len(scale) > 1 or len(offset) > 1 or scale[0] != 1 or offset[0] != 0:
                    # s_ += f"scale=bn_params['{layer_name}']['scale'], offset=bn_params['{layer_name}']['offset'],\nscale_shift_num=bn_params['{layer_name}']['scale_shift_num'], "
                    s_ += f"scale=c_{layer_name}_scale, offset=c_{layer_name}_offset, scale_shift_num=c_{layer_name}_scale_shift_num, "
                # else:
                #     s_ + f'jump_bn=True, '
                s_ += f"accumulate_shift_num={accumulate_shift_num}, \n"

                # noise
                s_ += f"DAC_noise=PE_in_noise, conductance_noise=PE_weight_noise, ADC_noise=PE_out_noise, ADC_offset=ADC_offset, relu={relu}, \n"
                s_ += f"device=device, is_scale_first={scale_first}, )"
            else:
                raise ValueError(f'Message translated to English.')
        else:
            raise ValueError(f'Message translated to English.')

        return s_

    fn_gen_fused_conv2d = fn_gen_conv2d


