    # transes

    def fn_gen_concat(self, layer_name, layer_info):

        s_ = '['
        c_ = 0
        for in_ in layer_info.inputs:
            s_ += f'{self.all_node[in_.ref]}'
            if c_ != len(layer_info.inputs) - 1:
                s_ += ', '
            c_ += 1
        s_ += ']'
        # attr
        axis = layer_info.op.axis
        return f'x_{layer_name} = CIMA_Concat({s_}, axis={axis})'

    # activate

    def fn_gen_relu(self, layer_name, layer_info):
        pre_layers = layer_info.inputs[0].ref
        return  f'x_{layer_name} = CIMA_Relu({self.all_node[pre_layers]})'


    def fn_gen_silu(self, layer_name, layer_info):
        # pre layers
        pre_layers = layer_info.inputs[0].ref
        # attr
        if ":" in pre_layers:
            pre_layers_ = pre_layers.split(':')[0]
        else:
            pre_layers_ = pre_layers
        data_type = self.layer_out_data_type[pre_layers_]

        if data_type == '4bit':
            return  f"x_{layer_name} = CIMA_SiLU_4bit({self.all_node[pre_layers]}, activation_lut['{layer_name}'])"
        elif data_type == '8bit':
            return  f"x_{layer_name} = CIMA_SiLU_8bit({self.all_node[pre_layers]}, activation_lut['{layer_name}'])"
        else:
            raise ValueError(f'Message translated to English.')
