    def fn_gen_mul_add(self, layer_name, layer_info):
        scale = layer_info.CIMA_calc_info.scale
        offset = layer_info.CIMA_calc_info.offset
        scale_shift_num = layer_info.CIMA_calc_info.scale_shift_num
        # data_type = layer_info.CIMA_calc_info.data_type
        pre_layers = layer_info.inputs[0].ref
        # attr
        if ":" in pre_layers:
            pre_layers_ = pre_layers.split(':')[0]
        else:
            pre_layers_ = pre_layers
        data_type = self.layer_out_data_type[pre_layers_]

        if data_type == '4bit':
            return f"x_{layer_name} = CIMA_Mul_Add_4bit({self.all_node[pre_layers]}, scale={scale}, offset={offset}, scale_shift_num={scale_shift_num})"
        elif data_type == '8bit':
            return f"x_{layer_name} = CIMA_Mul_Add_8bit({self.all_node[pre_layers]}, scale={scale}, offset={offset}, scale_shift_num={scale_shift_num})"
        else:
            raise ValueError(f'Message translated to English.')

    # resize

    def fn_gen_resize(self, layer_name, layer_info):

        pre_layer = layer_info.inputs[0].ref
        scale_factor = layer_info.op.scale[2:]
        return f"x_{layer_name} = CIMA_Resize({self.all_node[pre_layer]}, scale_factor={scale_factor})"



    # split
    def fn_gen_split(self, layer_name, layer_info):
        # attr
        dim = layer_info.op.axis
        channel = layer_info.op.split
        pre_layers = layer_info.inputs[0].ref

        s_ = ''
        c_ = 0
        for o in layer_info.outputs:
            s_ += f'x_{layer_name}_{c_}'
            if c_ != len(layer_info.outputs) - 1:
                s_ += ', '
            c_ += 1
        return f"{s_} = CIMA_Split({self.all_node[pre_layers]}, {channel}, dim={dim})"

    # split
    def fn_gen_fused_concat(self, layer_name, layer_info):
        # attr
        axis = layer_info.op.axis
        pre_layers = layer_info.inputs[0].ref
        split = layer_info.op.split
        silu = layer_info.op.silu
        # data type
        if ":" in pre_layers:
            pre_layers_ = pre_layers.split(':')[0]
        else:
            pre_layers_ = pre_layers
        data_type = self.layer_out_data_type[pre_layers_]
        # input
        in_s_ = '['
        c_ = 0
        for in_ in layer_info.inputs:
            in_s_ += f'{self.all_node[in_.ref]}'
            if c_ != len(layer_info.inputs) - 1:
                in_s_ += ', '
            c_ += 1
        in_s_ += ']'

        if split != None and silu != None:
            dim = layer_info.op.split.axis
            channel = layer_info.op.split.split
            s_ = ''
            c_ = 0
            for o in layer_info.outputs:
                s_ += f'x_{layer_name}_{c_}'
                if c_ != len(layer_info.outputs) - 1:
                    s_ += ', '
                c_ += 1
            if data_type == '4bit':
                return f"{s_} = CIMA_Concat_SiLU_Split_4bit({in_s_}, activation_lut['{layer_name}'], {axis}, {channel}, dim={dim})"
            elif data_type == '8bit':
                return f"{s_} = CIMA_Concat_SiLU_Split_8bit({in_s_}, activation_lut['{layer_name}'], {axis}, {channel}, dim={dim})"
            else:
                raise ValueError(f'Message translated to English.')
        elif split != None:
            dim = layer_info.op.split.axis
            channel = layer_info.op.split.split
            s_ = ''
            c_ = 0
            for o in layer_info.outputs:
                s_ += f'x_{layer_name}_{c_}'
                if c_ != len(layer_info.outputs) - 1:
                    s_ += ', '
                c_ += 1
            return f"{s_} = CIMA_Concat_Split({in_s_}, {axis}, {channel}, dim={dim})"
        elif silu != None:
            if data_type == '4bit':
                return f"x_{layer_name} = CIMA_Concat_SiLU_4bit({in_s_}, activation_lut['{layer_name}'], {axis})"
            elif data_type == '8bit':
                return f"x_{layer_name} = CIMA_Concat_SiLU_8bit({in_s_}, activation_lut['{layer_name}'], {axis})"
            else:
                raise ValueError(f'Message translated to English.')
        else:
            raise ValueError(f'Message translated to English.')

    # identity
    def fn_gen_identity(self, layer_name, layer_info):
        # attr
        pre_layers = layer_info.inputs[0].ref
        return f"x_{layer_name} = {self.all_node[pre_layers]}"

    # identity
    def fn_gen_flatten(self, layer_name, layer_info):
        # attr
        pre_layers = layer_info.inputs[0].ref
        start_dim = layer_info.op.start_dim
        return f"x_{layer_name} = torch.flatten({self.all_node[pre_layers]}, start_dim={start_dim})"

    # pad
    def fn_gen_pad(self, layer_name, layer_info):
        # attr
        pre_layers = layer_info.inputs[0].ref
        pads = layer_info.op.pads
        # IR attr to torch.Functional attr
        assert len(pads) % 2 == 0, f'Message translated to English.'
        pads_torch = []
        l = len(pads)//2
        for t in range(l-1, -1, -1):
            pads_torch.append(pads[t])
            pads_torch.append(pads[t+l])
        values = layer_info.op.value
        return f"x_{layer_name} = CIMA_Pad({self.all_node[pre_layers]}, pad={pads_torch}, value={values})"

    # type conversion
    def fn_gen_type_conversion(self, layer_name, layer_info):
        # attr
        in_dtype = layer_info.op.in_dtype
        out_dtype = layer_info.op.out_dtype
        assert in_dtype in ['4bit', '8bit']
        assert out_dtype in ['4bit', '8bit']
        pre_layers = layer_info.inputs[0].ref
        return f"x_{layer_name} = CIMA_{in_dtype}_to_{out_dtype}({self.all_node[pre_layers]})"
